const llmRaw = $input.item.json.choices?.[0]?.message?.content || '';
const grund = llmRaw.replace(/<think>[\s\S]*?<\/think>/gi, '').trim().replace(/^weil\s+/i, '') || 'mich Ihre Arbeit mit Automatisierung und KI überzeugt hat';

const job = $('DB: Jobs mit Email holen').item.json;
const firma = job.company_name || 'Ihr Unternehmen';
const stelle = job.job_title || 'die ausgeschriebene Stelle';

const body = `<div style="font-family: Arial, sans-serif; font-size: 15px; color: #1a1a1a; max-width: 520px; line-height: 1.7;">

<p style="margin: 0 0 20px 0;">Guten Tag,</p>

<p style="margin: 0 0 20px 0;">ich schreibe Ihnen bezüglich der Stelle als <strong>${stelle}</strong> bei ${firma}.</p>

<p style="margin: 0 0 20px 0;">Ich bin Automation Engineer aus Berlin (Python, n8n, LLM-Integration) und würde mich freuen, wenn Sie einen Blick in meinen Lebenslauf werfen — ich bewerbe mich, weil ${grund}.</p>

<p style="margin: 0 0 32px 0;">Vielen Dank für Ihre Zeit.</p>

<p style="margin: 0 0 32px 0;">Mit freundlichen Grüßen,<br><strong>Kirill Brüggemann</strong></p>

<hr style="border: none; border-top: 1px solid #e8e8e8; margin: 0 0 12px 0;">
<p style="margin: 0; font-size: 12px; color: #999; line-height: 2.4;">
<a href="https://drive.google.com/file/d/1HwbI0zcSySikQdV2yEJuaoeU-hyNaDVy/view" style="color: #555; text-decoration: none;">📄 Lebenslauf</a>
&nbsp;·&nbsp;
<a href="https://drive.google.com/file/d/1G2uANtdZywakvzyt4JJyA73tI4ilzO5W/view" style="color: #555; text-decoration: none;">📊 Portfolio</a>
&nbsp;·&nbsp;
<a href="https://github.com/KiBrueg" style="color: #555; text-decoration: none;">GitHub</a>
&nbsp;·&nbsp;
<a href="https://linkedin.com/in/ki-brueg-2520033bb" style="color: #555; text-decoration: none;">LinkedIn</a>
</p>

</div>`;

return {
  job_id: job.id,
  contact_email: job.contact_email,
  subject: `Bewerbung als ${stelle} (m/w/d) — Kirill Brüggemann`,
  body,
  firma,
  stelle
};

